#include <cmath>
#include <iostream>

class Fraction {
    int m_num{};
    int m_den{ 1 };

    static int gcd(int a, int b) {
        a = std::abs(a);
        b = std::abs(b);
        while (b != 0) {
            int t{ b };
            b = a % b;
            a = t;
        }
        return a;
    }

    void reduce() {
        if (m_den < 0) { m_num = -m_num; m_den = -m_den; }
        int g{ gcd(m_num, m_den) };
        m_num /= g;
        m_den /= g;
    }

public:
    Fraction(int num, int den) : m_num{ num }, m_den{ den } {
        reduce();
    }

    // TODO: overload operator* as a member function
    Fraction operator*(const Fraction& rhs) const {
        return Fraction{ 0, 1 };
    }

    void print() const {
        std::cout << m_num << '/' << m_den << '\n';
    }
};

int main() {
    int n1{}, d1{}, n2{}, d2{};
    std::cin >> n1 >> d1 >> n2 >> d2;
    Fraction a{ n1, d1 };
    Fraction b{ n2, d2 };
    Fraction c{ a * b };
    c.print();
    return 0;
}

